{
    "level": "A1–A2",
    "intro": "W tym temacie poznasz <strong>pytania tak/nie</strong>, czyli najprostszy typ pytań w języku angielskim.",
    "rules": [
        {
            "label": "Z DO/DOES/DID",
            "color": "emerald",
            "text": "<strong>Czasownik pomocniczy</strong> stawiamy przed podmiotem:",
            "example": "Do you like coffee? / Did they arrive?"
        },
        {
            "label": "Z TO BE",
            "color": "blue",
            "text": "<strong>To be</strong> samo przechodzi przed podmiot:",
            "example": "Are you ready? / Was she late?"
        },
        {
            "label": "Z MODALNYMI",
            "color": "amber",
            "text": "<strong>Czasownik modalny</strong> także stoi przed podmiotem:",
            "example": "Can you swim? / Will she come?"
        }
    ]
}

{
    "title": "1. Co to są pytania ogólne?",
    "intro": "Pytania tak/nie to pytania, na które zwykle odpowiadamy krótko:",
    "items": [
        {
            "label": "Pytanie",
            "title": "Do you like tea?",
            "subtitle": "Czy lubisz herbatę?"
        },
        {
            "label": "Odpowiedź twierdząca",
            "title": "Yes, I do.",
            "subtitle": "Tak."
        },
        {
            "label": "Odpowiedź przecząca",
            "title": "No, I don't.",
            "subtitle": "Nie."
        }
    ]
}

{
    "title": "2. Pytania z DO/DOES/DID",
    "sections": [
        {
            "label": "Present Simple",
            "color": "emerald",
            "description": "W Present Simple używamy <strong>do</strong> z I/you/we/they i <strong>does</strong> z he/she/it.",
            "examples": [
                {
                    "en": "Do you speak English?",
                    "ua": "Czy mówisz po angielsku?"
                },
                {
                    "en": "Do they live in Kyiv?",
                    "ua": "Czy oni mieszkają w Kijowie?"
                },
                {
                    "en": "Does she work here?",
                    "ua": "Czy ona tu pracuje?"
                },
                {
                    "en": "Does it work?",
                    "ua": "Czy to działa?"
                }
            ]
        },
        {
            "label": "Past Simple",
            "color": "sky",
            "description": "W Past Simple dla wszystkich osób używamy <strong>did</strong>, a czasownik główny zostaje w formie podstawowej.",
            "examples": [
                {
                    "en": "Did you see the film?",
                    "ua": "Czy widziałeś ten film?"
                },
                {
                    "en": "Did she call you?",
                    "ua": "Czy ona do ciebie dzwoniła?"
                },
                {
                    "en": "Did they arrive on time?",
                    "ua": "Czy przyjechali na czas?"
                },
                {
                    "en": "Did it rain yesterday?",
                    "ua": "Czy wczoraj padał deszcz?"
                }
            ]
        },
        {
            "label": "Struktura",
            "color": "purple",
            "description": "Ogólna formuła pytania z <strong>do/does/did</strong> wygląda tak:",
            "examples": [
                {
                    "en": "Do/Does/Did + subject + verb (base form) + ...?",
                    "ua": "Do/Does/Did + podmiot + czasownik w formie podstawowej + ...?"
                }
            ],
            "note": "📌 Po <strong>does</strong> i <strong>did</strong> nie dodajemy już końcówki <strong>-s</strong> ani <strong>-ed</strong> do głównego czasownika."
        }
    ]
}

{
    "title": "3. Pytania z TO BE",
    "sections": [
        {
            "label": "Present Simple",
            "color": "blue",
            "description": "Z czasownikiem <strong>to be</strong> po prostu stawiamy formę czasownika przed podmiotem.",
            "examples": [
                {
                    "en": "Are you ready?",
                    "ua": "Czy jesteś gotowy?"
                },
                {
                    "en": "Is she a teacher?",
                    "ua": "Czy ona jest nauczycielką?"
                },
                {
                    "en": "Are they at home?",
                    "ua": "Czy oni są w domu?"
                },
                {
                    "en": "Is it expensive?",
                    "ua": "Czy to jest drogie?"
                }
            ]
        },
        {
            "label": "Past Simple",
            "color": "amber",
            "description": "W czasie przeszłym używamy <strong>was</strong> albo <strong>were</strong> przed podmiotem.",
            "examples": [
                {
                    "en": "Was he at work yesterday?",
                    "ua": "Czy on był wczoraj w pracy?"
                },
                {
                    "en": "Were you tired?",
                    "ua": "Czy byłeś zmęczony?"
                },
                {
                    "en": "Were they happy?",
                    "ua": "Czy byli szczęśliwi?"
                },
                {
                    "en": "Was it difficult?",
                    "ua": "Czy to było trudne?"
                }
            ]
        },
        {
            "label": "Struktura",
            "color": "rose",
            "description": "Formuła pytania z <strong>to be</strong> jest bardzo prosta:",
            "examples": [
                {
                    "en": "Am/Is/Are/Was/Were + subject + ...?",
                    "ua": "Am/Is/Are/Was/Were + podmiot + ...?"
                }
            ],
            "note": "📌 Z <strong>to be</strong> nie dodajemy już <strong>do/does/did</strong>."
        }
    ]
}

{
    "title": "4. Pytania z czasownikami modalnymi",
    "sections": [
        {
            "label": "CAN / COULD",
            "color": "emerald",
            "description": "W pytaniach z <strong>can</strong> i <strong>could</strong> modal stoi przed podmiotem.",
            "examples": [
                {
                    "en": "Can you swim?",
                    "ua": "Czy umiesz pływać?"
                },
                {
                    "en": "Can she drive?",
                    "ua": "Czy ona umie prowadzić?"
                },
                {
                    "en": "Could you help me?",
                    "ua": "Czy mógłbyś mi pomóc?"
                },
                {
                    "en": "Could they come?",
                    "ua": "Czy mogliby przyjść?"
                }
            ]
        },
        {
            "label": "WILL / WOULD",
            "color": "sky",
            "description": "Tak samo działają <strong>will</strong> i <strong>would</strong>.",
            "examples": [
                {
                    "en": "Will you come?",
                    "ua": "Czy przyjdziesz?"
                },
                {
                    "en": "Will it rain?",
                    "ua": "Czy będzie padać?"
                },
                {
                    "en": "Would you like some coffee?",
                    "ua": "Czy chciałbyś kawy?"
                },
                {
                    "en": "Would she agree?",
                    "ua": "Czy ona by się zgodziła?"
                }
            ]
        },
        {
            "label": "SHOULD / MUST / MAY",
            "color": "purple",
            "description": "Pozostałe modale tworzą pytania dokładnie w ten sam sposób.",
            "examples": [
                {
                    "en": "Should we go?",
                    "ua": "Czy powinniśmy iść?"
                },
                {
                    "en": "Must I wait?",
                    "ua": "Czy muszę czekać?"
                },
                {
                    "en": "May I ask?",
                    "ua": "Czy mogę zapytać?"
                }
            ],
            "note": "📌 Struktura: <strong>modal + podmiot + czasownik podstawowy</strong>."
        }
    ]
}

{
    "title": "5. Pytania z HAVE GOT i HAVE",
    "sections": [
        {
            "label": "HAVE GOT / HAS GOT",
            "color": "blue",
            "description": "W brytyjskim angielskim często pytamy o posiadanie za pomocą <strong>have got</strong>.",
            "examples": [
                {
                    "en": "Have you got a car?",
                    "ua": "Czy masz samochód?"
                },
                {
                    "en": "Has she got a dog?",
                    "ua": "Czy ona ma psa?"
                },
                {
                    "en": "Have they got time?",
                    "ua": "Czy oni mają czas?"
                }
            ]
        },
        {
            "label": "HAVE / HAS (posiadanie)",
            "color": "amber",
            "description": "W amerykańskim angielskim częściej używa się <strong>do/does</strong> z czasownikiem <strong>have</strong>.",
            "examples": [
                {
                    "en": "Do you have a car?",
                    "ua": "Czy masz samochód?"
                },
                {
                    "en": "Does she have a dog?",
                    "ua": "Czy ona ma psa?"
                },
                {
                    "en": "Do they have time?",
                    "ua": "Czy oni mają czas?"
                }
            ],
            "note": "📌 W brytyjskim angielskim częściej spotkasz <strong>have got</strong>, a w amerykańskim — <strong>have</strong> z <strong>do/does</strong>."
        }
    ]
}

{
    "title": "6. Inne czasy",
    "sections": [
        {
            "label": "Present Continuous",
            "color": "emerald",
            "description": "W Present Continuous pomocnicze <strong>am/is/are</strong> przechodzi przed podmiot.",
            "examples": [
                {
                    "en": "Are you working now?",
                    "ua": "Czy teraz pracujesz?"
                },
                {
                    "en": "Is she coming?",
                    "ua": "Czy ona przychodzi?"
                },
                {
                    "en": "Are they playing?",
                    "ua": "Czy oni grają?"
                }
            ]
        },
        {
            "label": "Present Perfect",
            "color": "sky",
            "description": "W Present Perfect używamy <strong>have</strong> albo <strong>has</strong> przed podmiotem.",
            "examples": [
                {
                    "en": "Have you seen this film?",
                    "ua": "Czy widziałeś ten film?"
                },
                {
                    "en": "Has she finished?",
                    "ua": "Czy ona już skończyła?"
                },
                {
                    "en": "Have they arrived?",
                    "ua": "Czy oni już przyjechali?"
                }
            ]
        },
        {
            "label": "Past Continuous",
            "color": "purple",
            "description": "W Past Continuous pytanie tworzymy przez przesunięcie <strong>was/were</strong> przed podmiot.",
            "examples": [
                {
                    "en": "Were you sleeping?",
                    "ua": "Czy spałeś?"
                },
                {
                    "en": "Was she studying?",
                    "ua": "Czy ona się uczyła?"
                },
                {
                    "en": "Were they watching TV?",
                    "ua": "Czy oni oglądali telewizję?"
                }
            ],
            "note": "📌 Zasada jest zawsze ta sama: <strong>czasownik pomocniczy przed podmiotem</strong>."
        }
    ]
}

{
    "title": "7. Tabela porównawcza",
    "intro": "Tak tworzymy pytania ogólne z różnymi typami czasowników:",
    "rows": [
        {
            "en": "Simple tenses (do/does/did)",
            "ua": "Czasy proste",
            "note": "Do you like...? / Does she work...? / Did they arrive?"
        },
        {
            "en": "To be (am/is/are/was/were)",
            "ua": "Czasownik to be",
            "note": "Are you ready? / Is she here? / Were they happy?"
        },
        {
            "en": "Modals (can/will/should...)",
            "ua": "Czasowniki modalne",
            "note": "Can you swim? / Will she come?"
        },
        {
            "en": "Have got / have",
            "ua": "Posiadanie",
            "note": "Have you got a car? / Do you have a car?"
        },
        {
            "en": "Continuous tenses (am/is/are/was/were + -ing)",
            "ua": "Czasy ciągłe",
            "note": "Are you working? / Were they watching TV?"
        },
        {
            "en": "Perfect tenses (have/has + V3)",
            "ua": "Czasy perfect",
            "note": "Have you seen it? / Has she finished?"
        }
    ],
    "warning": "📌 Podstawowa zasada: <strong>czasownik pomocniczy stoi przed podmiotem</strong>."
}

{
    "title": "8. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Podmiot stoi przed czasownikiem zamiast po nim.",
            "wrong": "❌ You are ready?",
            "right": "✅ <span class=\"font-mono\">Are you ready?</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Dodawanie <strong>do/does</strong> do czasownika <strong>to be</strong>.",
            "wrong": "❌ Do you are tired?",
            "right": "✅ <span class=\"font-mono\">Are you tired?</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Niepoprawna forma głównego czasownika po <strong>does</strong> lub <strong>did</strong>.",
            "wrong": "❌ Does she works here?",
            "right": "✅ <span class=\"font-mono\">Does she work here?</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Brak czasownika pomocniczego w pytaniu.",
            "wrong": "❌ She work here?",
            "right": "✅ <span class=\"font-mono\">Does she work here?</span>"
        }
    ]
}

{
    "title": "10. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwą opcję",
    "select_intro": "Wybierz poprawną formę pytania ogólnego.",
    "selects": [
        {
            "label": "a) Do you like coffee? / b) Does you like coffee? / c) Like you coffee?",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Is she ready? / b) Does she ready? / c) She is ready?",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Can you swim? / b) Do you can swim? / c) Swim you?",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Did they arrive? / b) Were they arrive? / c) They did arrive?",
            "prompt": "Która opcja jest poprawna?"
        }
    ],
    "options": [
        "a",
        "b",
        "c"
    ],
    "input_title": "Ćwiczenie 2. Utwórz pytanie",
    "input_intro": "Utwórz pytanie tak/nie z podanego zdania.",
    "inputs": [
        {
            "before": "She likes tea. → ",
            "after": ""
        },
        {
            "before": "They are ready. → ",
            "after": ""
        },
        {
            "before": "He can drive. → ",
            "after": ""
        },
        {
            "before": "They arrived early. → ",
            "after": ""
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w pytaniu.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "You are ready?",
            "example_target": "Are you ready?"
        },
        {
            "original": "1. Does she works here?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Do they are at home?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "3. Did he went there?",
            "placeholder": "Popraw błąd"
        }
    ]
}

{
    "title": "Inne lekcje w tej sekcji",
    "items": [
        {
            "label": "Formy pytań",
            "current": false
        },
        {
            "label": "Pytania typu yes / no",
            "current": true
        },
        {
            "label": "Pytania szczegółowe (wh-)",
            "current": false
        },
