            "label": "Odpowiedzi na pytania",
            "current": false
        },
        {
            "label": "Pytania alternatywne",
            "current": false
        },
        {
            "label": "Pytania rozłączne (question tags)",
            "current": false
        },
        {
            "label": "Pytania przeczące",
            "current": false
        }
    ]
}
